import{_ as e,o as r,c as a,a2 as o}from"./chunks/framework.BWuWLRhz.js";const l="/images/toddler/0-birth.png",s="/images/toddler/1-nap-schedule.png",n="/images/toddler/2-snoo-1.png",i="/images/toddler/3-cow-says-moo.png",h="/images/toddler/4-stalin-1.png",p="/images/toddler/5-I-love-mommy-2.png",d="/images/toddler/6-video-stranger-1.png",m="/images/toddler/7-circles.png",g="/images/toddler/8-sneeze-3.png",c="/images/toddler/9-spectrum-4.png",_="/images/toddler/10-cotton-candy.png",f="/images/toddler/11-advice-1.png",u="/images/toddler/pinit_fg_en_rect_gray_20.png",x=JSON.parse('{"title":"Tales from Toddlerhood","description":"","frontmatter":{"title":"Tales from Toddlerhood","titleZh":"幼儿趣事","date":"2025-10-24T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2025/10/toddler.html","slug":"toddler"},"headers":[],"relativePath":"posts/toddler.md","filePath":"posts/toddler.md","lastUpdated":1782886257000}'),b={name:"posts/toddler.md"};function w(k,t,y,q,T,P){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="幼儿趣事-·-tales-from-toddlerhood" tabindex="-1">幼儿趣事 · Tales from Toddlerhood <a class="header-anchor" href="#幼儿趣事-·-tales-from-toddlerhood" aria-label="Permalink to &quot;幼儿趣事 · Tales from Toddlerhood&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2025/10/toddler.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2025/10/toddler.html</a> · 2025-10-24</p></blockquote><p>早在 2023 年,我写过一篇<a href="https://waitbutwhy.com/2023/05/baby.html" target="_blank" rel="noreferrer">博客</a>,讲我第一次当爹以及为此被搞得晕头转向的一切。</p><p>今年早些时候,这事儿又发生了一次。就这样,我又回到了这里:</p><p><img src="'+l+'" alt=""></p><p>一方面,现在时间已经彻底不存在了。</p><p><img src="'+s+'" alt=""></p><p>另一方面,老二……比老大好带。</p><p><img src="'+n+'" alt=""></p><p>不过我今天不是来聊新生儿的,尽管她可爱又肥硕。今天我要从「幼儿父母」这个深渊向你汇报战况。我一直以为两岁小孩基本上就是个感冒了的、无意识的一坨,结果发现他们竟然是真人,你能跟他们建立关系。跟一个两岁小孩共同生活了一段时间后,我得出了以下发现:</p><h3 id="_1-你可以同时既彻底痴迷于一个人-又被这个人无聊得死去活来。" tabindex="-1"><strong>1) 你可以同时既彻底痴迷于一个人,又被这个人无聊得死去活来。</strong> <a class="header-anchor" href="#_1-你可以同时既彻底痴迷于一个人-又被这个人无聊得死去活来。" aria-label="Permalink to &quot;**1) 你可以同时既彻底痴迷于一个人,又被这个人无聊得死去活来。**&quot;">​</a></h3><p>有时候我在办公室工作,女儿会摇摇晃晃走进来,冲过来抱我一下。这毫无疑问是我一天里最棒的时刻。她的笑容让我充满纯粹的喜悦。她的小奶音是天堂直接送来的。我对她怀有最纯粹的爱。</p><p>只不过,我也觉得她无聊得开天辟地。跟她玩五分钟是一回事,但当我在一个下午的深处陪着她,除了「我刚跟一个 IQ 20 的人相处了三小时」以外,实在很难得出别的结论。</p><p><img src="'+i+'" alt="toddler: The cow says moo! parent, lying on ground: It does."></p><h3 id="_2-幼儿是混蛋。" tabindex="-1"><strong>2) 幼儿是混蛋。</strong> <a class="header-anchor" href="#_2-幼儿是混蛋。" aria-label="Permalink to &quot;**2) 幼儿是混蛋。**&quot;">​</a></h3><p>众所周知,幼儿说变就能变成 20 世纪中叶的极权独裁者。</p><p><img src="'+h+'" alt=""></p><p>但他们混蛋的地方还有一些没那么显眼的。前几天,我女儿在玩乐高。我坐到她旁边,问她在搭什么,她回:「爸爸是不是要去办公室工作了?」——一句毫不含蓄的暗示,让我他妈的赶紧滚开。</p><p>或者,我用心用爱给她做了一整份饭,她连一口都不肯吃,搞得我替自己觉得<a href="https://waitbutwhy.com/2016/05/clueyness-a-weird-kind-of-sad.html" target="_blank" rel="noreferrer">脑子不太清醒</a>。</p><p>最近呢,我犯了个错误——告诉了她我的年龄,现在她一天要说 30 遍「爸爸 43 岁了」,持续给我灌输存在主义的恐惧。</p><p><img src="'+p+`" alt="dad: I love you.
toddler: I love mommy."></p><h3 id="_3-没人想看别人家娃的视频。" tabindex="-1"><strong>3) 没人想看别人家娃的视频。</strong> <a class="header-anchor" href="#_3-没人想看别人家娃的视频。" aria-label="Permalink to &quot;**3) 没人想看别人家娃的视频。**&quot;">​</a></h3><p>幼儿父母身处一个现实扭曲力场中,这让人很难记住:大多数人觉得你家小孩无聊到令人窒息。<a href="#footnote-1-10661">1</a></p><p><img src="`+d+'" alt="showing a stranger a video of your kid: Aw so cute! (thought bubble: Oh my god it&#39;s not even halfway done.)"></p><p>有小孩的朋友,如果孩子年龄相仿,就相当于组成了一个「同期群」,所以有小孩的父母生活里往往会突然冒出一大堆同龄小孩。在我这个圈子里,我既是「强行给别人看小孩视频」的加害者,也是频繁的受害者。这是我们都得交的税。<a href="#footnote-2-10661">2</a></p><p>我自己这边至少尽量把伤害降到最小。</p><p><img src="'+m+'" alt="Three circles showing who I send toddler/baby photos and videos to: tiny circle labeled Friends, slightly bigger circle labeled Family, and huge circle labeled Wife"></p><h3 id="_4-别人家的小孩能毁掉你一整周。" tabindex="-1"><strong>4) 别人家的小孩能毁掉你一整周。</strong> <a class="header-anchor" href="#_4-别人家的小孩能毁掉你一整周。" aria-label="Permalink to &quot;**4) 别人家的小孩能毁掉你一整周。**&quot;">​</a></h3><p><img src="'+g+'" alt=""></p><h3 id="_5-小孩既是天才又是笨蛋。" tabindex="-1"><strong>5) 小孩既是天才又是笨蛋。</strong> <a class="header-anchor" href="#_5-小孩既是天才又是笨蛋。" aria-label="Permalink to &quot;**5) 小孩既是天才又是笨蛋。**&quot;">​</a></h3><p>如果我带我女儿去中国住一年,期间完全不上语言课,我回来的时候大概能会六个中文单词,而她会说得很流利。小孩光靠听就能学会一门语言,这对我来说完全说不通,但他们就是能。他们是怪胎级别的天才。可她想要草莓的时候会说「你要吃草莓吗?」,因为我们说「你」的时候,是<a href="https://www.youtube.com/watch?v=K-q-3fPYw_Y" target="_blank" rel="noreferrer">指她</a>,所以她现在觉得「你」是她名字的同义词,这就非常不天才了。</p><p>同样,前几天我第一次给她读一本新书,读第二遍的时候,她中途把我拦下来纠正我说错的地方。原来我不小心跳过了一个词,而她之所以知道,是因为她第一遍就把整本书背下来了。可我们换一本书,她又能盯着一页看一万年,找乔治猴「藏」在哪里——尽管他就他妈明晃晃地在那儿。</p><h3 id="_6-小孩的世界观极其不准确。" tabindex="-1"><strong>6) 小孩的世界观极其不准确。</strong> <a class="header-anchor" href="#_6-小孩的世界观极其不准确。" aria-label="Permalink to &quot;**6) 小孩的世界观极其不准确。**&quot;">​</a></h3><p>我们有时会带女儿去图书馆的故事时间,图书管理员会给一群小孩读书。第一次带她去的时候,她决定亲自上手,故事讲到一半就走过去坐到管理员腿上。问题在于,她还没完全搞清楚这个世界并不是完全为她的利益而存在的。</p><p>也能理解。你刚出生的头几年,见到的每个人都对你微笑挥手,所以你会高估自己的重要性。只有慢慢地你才会搞清楚到底是怎么回事。<a href="#footnote-3-10661">3</a></p><p><img src="'+c+'" alt=""></p><p>这属于「小孩根本不知道发生了什么」这个更宏观现象的一部分。他们不知道死亡、钱、历史、性、宇宙大爆炸,也基本不知道任何关于现实的事。他们就这么凭空冒出来,开始存在,而不知为何,他们并不觉得这事很怪或者很让人困惑。</p><p>(一个不错的「你到底知不知道发生了什么」试金石测试是:如果你走在街上,一头大象从天上飞下来,悬停在你头顶十英尺处,用一种傻乎乎的卡通嗓音跟你打了声招呼,然后又飞走了,你的反应会是「我的天呐刚刚发生了什么」还是耸耸肩说「嗯,这种事偶尔会发生」?如果是后者,那你对世界毫无概念。大多数两岁小孩通不过这个测试。)</p><h3 id="_7-幼儿是世界上最好笑也是最不好笑的人。" tabindex="-1"><strong>7) 幼儿是世界上最好笑也是最不好笑的人。</strong> <a class="header-anchor" href="#_7-幼儿是世界上最好笑也是最不好笑的人。" aria-label="Permalink to &quot;**7) 幼儿是世界上最好笑也是最不好笑的人。**&quot;">​</a></h3><p>我女儿一点都不好笑,真的一点都不。有一次她把东西掉在地上,我说了句「扑通」,她觉得简直是他妈的全世界最爆笑的事。接下来十分钟,她一直捡东西、扔东西、说「扑通」,每次都笑得歇斯底里。</p><p>但无意之间,她是个喜剧天才。前几天我挡了她的路,她说:「你能从空间里出去吗?」现在我和我老婆想让对方让路时都这么说。还有一次我们得撕掉她腿上的创可贴,撕完之后她说:「我好完美地难过。」现在我和我老婆一有什么不开心的事就这么说。<a href="#footnote-4-10661">4</a></p><p>我们还发现一个神奇的窍门:你可以教幼儿说任何你想让她说的话。我们教她每次摔倒就说「妈妈咪呀」,强烈推荐给其他幼儿家长。</p><h3 id="_8-幼儿家长意见都非常强烈-而且每个人都非常爱评判别人。" tabindex="-1"><strong>8) 幼儿家长意见都非常强烈,而且每个人都非常爱评判别人。</strong> <a class="header-anchor" href="#_8-幼儿家长意见都非常强烈-而且每个人都非常爱评判别人。" aria-label="Permalink to &quot;**8) 幼儿家长意见都非常强烈,而且每个人都非常爱评判别人。**&quot;">​</a></h3><p><img src="'+_+'" alt="Two parents silently judging each other. The parent of the toddler without cotton candy thinks: Imagine giving that to your kid. The parent of the toddler with cotton candy thinks: Imagine depriving your kid of that."></p><p>问题是,每一种强烈观点都有一种同样强烈的反面观点。</p><p><img src="'+f+'" alt="pairings of competing parenting advice, like: Toddlers thrive on routine vs Follow their natural rhythms and cues, and Supervision vs Freedom."></p><p>我已经开始接受一个事实:各种各样的事我都在搞砸,所以主要就是想跟我的小朋友玩得开心。要说我有什么策略的话,基本上就是:</p><ul><li>花大量(不看手机的)时间陪她</li><li>让她看到世界是个有趣又迷人的地方</li><li>鼓励她<a href="https://waitbutwhy.com/2015/11/the-cook-and-the-chef-musks-secret-sauce.html" target="_blank" rel="noreferrer">从第一性原理出发思考</a></li><li>在她专注或发呆时不打扰她;帮她学会享受自己的思维</li><li>避免设立一堆琐碎的规则,但一旦有规则,就要坚定执行</li><li>培养她解决问题的自信,让她成为一个会说「我想自己搞清楚方向」的人,而不是一个会说「我们问问人吧」的人</li></ul><p>幼儿家长可以自我安慰的一点是:养育方式的影响可能比我们以为的要小得多。与其试图去塑造这些两英尺高的小伙伴,不如引导他们成为他们本来就是的那个最好的自己。</p><h2 id="好了-得走了。该第-57-次读《吱吱鼠喜欢他的家-squeak-the-mouse-likes-his-house-》了。" tabindex="-1">好了,得走了。该第 57 次读《吱吱鼠喜欢他的家 (Squeak the Mouse Likes His House)》了。 <a class="header-anchor" href="#好了-得走了。该第-57-次读《吱吱鼠喜欢他的家-squeak-the-mouse-likes-his-house-》了。" aria-label="Permalink to &quot;好了,得走了。该第 57 次读《吱吱鼠喜欢他的家 (Squeak the Mouse Likes His House)》了。&quot;">​</a></h2><p><strong>更多为人父的故事:</strong> <a href="https://waitbutwhy.com/2023/05/baby.html" target="_blank" rel="noreferrer"><strong>第四孕期的 10 个想法</strong></a></p><p><strong>我最喜欢的幼儿绘本:</strong> <strong><a href="https://amzn.to/474Qe8D" target="_blank" rel="noreferrer">Flotsam</a>、<a href="https://amzn.to/43sPIPl" target="_blank" rel="noreferrer">Little Fur Family</a>、<a href="https://amzn.to/4hzjsQz" target="_blank" rel="noreferrer">The Giant Jam Sandwich</a>、<a href="https://amzn.to/3JrXRwP" target="_blank" rel="noreferrer">Little Owl&#39;s Night</a></strong></p><p><strong>如果你宁愿读点跟我家胖娃无关的东西:</strong></p><p><strong><a href="https://waitbutwhy.com/2016/09/marriage-decision.html" target="_blank" rel="noreferrer">结婚这个决定:要么永远,要么永不</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">驯服猛犸象:为什么你该停止在乎别人怎么想</a></strong></p><h2 id="为什么我总是迟到" tabindex="-1"><a href="https://waitbutwhy.com/2015/07/why-im-always-late.html" target="_blank" rel="noreferrer"><strong>为什么我总是迟到</strong></a> <a class="header-anchor" href="#为什么我总是迟到" aria-label="Permalink to &quot;[**为什么我总是迟到**](https://waitbutwhy.com/2015/07/why-im-always-late.html)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,可以订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**,新文章发布时我们会通知你。</p><p>想支持 Wait But Why,可以访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><hr><ol><li><p>幼儿的爷爷奶奶外公外婆可能是个例外,不过他们的态度跨度很大,一端是「求求你消失一个月,把孩子留给我」,另一端则是「我陪他们玩五分钟,纯粹是因为不玩显得不好看」。后一端的那些老人,和其他人一样觉得幼儿视频无聊透顶。<a href="#note-1-10661">↩</a></p></li><li><p>这里也有区间。一个好朋友发来的、简短高质量的自家娃视频短信(这样你可以自己找时间看,不用全程做出反应),没问题——甚至挺不错。而一个你几乎不认识的人当面给你放很长的幼儿视频,那就是噩梦了。<a href="#note-2-10661">↩</a></p></li><li><p><a href="https://www.amazon.com/Denial-Death-Ernest-Becker/dp/0684832402" target="_blank" rel="noreferrer">有人认为</a>,人们对名声的普遍渴望,在某种潜意识层面上,是想找回那种全世界都认识并爱着你的、早已失去的感觉。<a href="#note-3-10661">↩</a></p></li><li><p>她实际上说的是「我能出太空吗?」和「你好完美地悲伤」,因为,再说一遍,她还搞不清代词。<a href="#note-4-10661">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2025/10/toddler.html&amp;description=Tales%20from%20Toddlerhood" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p>',62)])])}const I=e(b,[["render",w]]);export{x as __pageData,I as default};
